1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string };
4	type Step = { items: Item[] };
5	type Scenario = { steps: Step[] };
6	
7	export function processScenario(scenario: unknown): unknown {
8	  const { steps } = scenario as Scenario;
9	  const items = steps[0].items;
10	  let basePremium = 0;
11	  for (const item of items) {
12	    if (item.type === "sword") basePremium += 100;
13	  }
14	  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
15	}
